1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	  moonstone: 25,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
11	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
12	const LOYALTY_DISCOUNT_RATE = 0.2;
13	const LOYALTY_YEARS_THRESHOLD = 2;
14	const CURSED_SURCHARGE_RATE = 0.5;
15	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
16	const HIGH_ENCHANTMENT_THRESHOLD = 5;
17	const PROCESSING_FEE = 5;
18	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
19	const COMPONENT_BLOCK_SIZE = 3;
20	const COMPONENT_BLOCK_BASE = 60;
21	
22	const INSURANCE_VALUES: Record<string, number> = {
23	  sword: 1000,
24	  amulet: 600,
25	  staff: 800,
26	  potion: 400,
27	  rune: 250,
28	  moonstone: 250,
29	};
30	
31	const CAP_MULTIPLIER = 2;
32	const DEDUCTIBLE = 100;
33	
34	const baseForType = (type: string, count: number): number => {
35	  if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
36	    return COMPONENT_BLOCK_BASE;
37	  }
38	  return count * BASE_PREMIUMS[type];
39	};
40	
41	export const runScenario = (scenario: any): unknown => {
42	  const results = [];
43	  let quoteStepsSeen = 0;
44	  const policiesByStepIndex = new Map<number, { capRemaining: number; items: any[] }>();
45	  for (let stepIndex = 0; stepIndex < scenario.steps.length; stepIndex++) {
46	    const step = scenario.steps[stepIndex];
47	    if (step.op === "claim") {
48	      for (const damage of step.incident.damages) {
49	        if (damage.amount < 0) {
50	          throw new Error(`damage amount must be non-negative`);
51	        }
52	      }
53	      const policy = policiesByStepIndex.get(step.policy)!;
54	      const insuredCountsByType = new Map<string, number>();
55	      for (const item of policy.items) {
56	        insuredCountsByType.set(item.type, (insuredCountsByType.get(item.type) ?? 0) + 1);
57	      }
58	      const damageCountsByType = new Map<string, number>();
59	      for (const damage of step.incident.damages) {
60	        damageCountsByType.set(damage.itemType, (damageCountsByType.get(damage.itemType) ?? 0) + 1);
61	      }
62	      for (const [type, count] of damageCountsByType) {
63	        if (count > (insuredCountsByType.get(type) ?? 0)) {
64	          throw new Error(`damage count for ${type} exceeds insured items`);
65	        }
66	      }
67	      let payout = 0;
68	      for (const damage of step.incident.damages) {
69	        const insuredItem = policy.items.find((i: any) => i.type === damage.itemType);
70	        let base = damage.amount;
71	        if (insuredItem && insuredItem.enchantment >= 8) {
72	          base = base * 0.5;
73	        } else if (insuredItem && insuredItem.material === "dragon") {
74	          base = base;
75	        }
76	        payout += Math.max(0, base - DEDUCTIBLE);
77	      }
78	      payout = Math.min(payout, policy.capRemaining);
79	      policy.capRemaining -= payout;
80	      results.push({ payout, remainingCap: policy.capRemaining });
81	      continue;
82	    }
83	    const items = step.items;
84	    for (const item of items) {
85	      if (!(item.type in BASE_PREMIUMS)) {
86	        throw new Error(`unknown item type: ${item.type}`);
87	      }
88	    }
89	    const countsByType = new Map<string, number>();
90	    for (const item of items) {
91	      countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
92	    }
93	    let itemBasesSum = 0;
94	    for (const [type, count] of countsByType) {
95	      itemBasesSum += baseForType(type, count);
96	    }
97	    let itemSurcharges = 0;
98	    let insuranceSum = 0;
99	    for (const item of items) {
100	      const itemBase = BASE_PREMIUMS[item.type];
101	      if (item.cursed) {
102	        itemSurcharges += itemBase * CURSED_SURCHARGE_RATE;
103	      }
104	      if (item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
105	        itemSurcharges += itemBase * HIGH_ENCHANTMENT_SURCHARGE_RATE;
106	      }
107	      insuranceSum += INSURANCE_VALUES[item.type];
108	    }
109	    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
110	      ? itemBasesSum * LOYALTY_DISCOUNT_RATE
111	      : 0;
112	    const followUpDiscount = quoteStepsSeen > 0
113	      ? itemBasesSum * FOLLOW_UP_DISCOUNT_RATE
114	      : 0;
115	    const itemsTotal = itemBasesSum + itemBasesSum * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount - followUpDiscount + itemSurcharges;
116	    const premium = Math.ceil(itemsTotal + PROCESSING_FEE);
117	    results.push({ premium });
118	    policiesByStepIndex.set(stepIndex, { capRemaining: insuranceSum * CAP_MULTIPLIER, items });
119	    quoteStepsSeen++;
120	  }
121	  return { results };
122	};
